&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पानी दो रास्तों से पहुँचाया जाता है:
	&lt;ul&gt;
		&lt;li&gt;एपोप्लास्ट - यह प्लाज्मा झिल्ली के बाहर का मार्ग है और इसमें कोशिका भित्ति और अंतरकोशिकीय स्थान शामिल हैं।&lt;/li&gt;
		&lt;li&gt;सिम्प्लास्ट - यह आसन्न कोशिकाओं के प्रोटोप्लाज्म को संदर्भित करता है जो प्लास्मोडेसमाटा के माध्यम से जुड़े होते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;कैस्पेरी पट्टियाँ&lt;/span&gt; कोशिका भित्ति के निक्षेप होते हैं और इसलिए &lt;strong&gt;एपोप्लास्ट मार्ग में एक अवरोध बनाते हैं&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;सामग्री को सिम्प्लास्ट मार्ग में अर्ध-पारगम्य प्लाज्मा झिल्ली से गुजरने के लिए मजबूर किए जाने के कारण&amp;nbsp;&lt;/span&gt;यह &lt;strong&gt;चयनात्मक &lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;अवशोषण&lt;/span&gt;&lt;strong&gt;&amp;nbsp;की अनुमति देता है&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;वे मिट्टी से &lt;strong&gt;पानी और पोषक तत्वों के अवशोषण को विनियमित&lt;/strong&gt; करने में मदद करते हैं।&lt;/li&gt;
	&lt;li&gt;वे जाइलम &lt;strong&gt;में अतिरिक्त पानी को प्रवेश करने से रोकने&lt;/strong&gt; के लिए एक प्रसार अवरोध की तरह कार्य करते हैं।&lt;/li&gt;
&lt;/ul&gt;
